import{_ as a,o as t,c as d,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Apple Ads Data & Reporting","description":"","frontmatter":{"title":"Apple Ads Data & Reporting","slug":"apple-ads-data-reporting"},"headers":[],"relativePath":"marketer-hub/apple-ads-data-reporting.md","filePath":"marketer-hub/apple-ads-data-reporting.md"}'),o={name:"marketer-hub/apple-ads-data-reporting.md"};function i(l,e,n,s,c,p){return t(),d("div",null,[...e[0]||(e[0]=[r('<h2 id="view-attribution-on-dashboard" tabindex="-1">View attribution on Dashboard <a class="header-anchor" href="#view-attribution-on-dashboard" aria-label="Permalink to &quot;View attribution on Dashboard&quot;">​</a></h2><p>All attribution is visible on the <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard summary page</a>.</p><p>All <strong>installs</strong>, <strong>opens</strong>, and <strong>view-through conversions (VTCs)</strong> registered from this channel will automatically be tagged with the <code>channel</code>: <code>Apple App Store</code> and the <code>Ad Partner</code>: <code>Apple Ads</code>. The <code>campaign</code> will be set to the Campaign Name you&#39;ve configured in the Apple Ads dashboard.</p><p>Due to <a href="https://searchads.apple.com/help/reporting/0028-apple-ads-attribution-api" target="_blank" rel="noreferrer">Apple&#39;s attribution API limitations</a>, it may take up to 30 days for full attribution of a device.</p><p>Note that these stats are <strong>limited to the date range</strong> at the top of the page. You can expand the range if you&#39;d like.</p><div class="info custom-block"><p class="custom-block-title">Note</p><ul><li>To view the cost metrics Branch provides, please see <a href="./what-is-a-self-attributing-network.html#san-cost-data">SAN Cost Data</a>.</li><li>If you&#39;re seeing discrepancies, please see <a href="./common-sources-of-san-reporting-discrepancies.html">Common Sources of SAN Reporting Discrepancies</a>.</li></ul></div><h3 id="incompatible-dimensions" tabindex="-1">Incompatible dimensions <a class="header-anchor" href="#incompatible-dimensions" aria-label="Permalink to &quot;Incompatible dimensions&quot;">​</a></h3><p>For some dimensions, you will see special callouts before adding them to your reports. Based on which dimensions are added, Branch will select the appropriate data source. If there is a clash between dimensions, we&#39;ll select a <a href="./paid-ads-analytics.html">&quot;default&quot; data source</a>. Branch will also provide warning icons to describe the collision:</p><h3 id="keyword-id" tabindex="-1">Keyword ID <a class="header-anchor" href="#keyword-id" aria-label="Permalink to &quot;Keyword ID&quot;">​</a></h3><p>With the new framework, <code>keywordId</code> is also passed to Branch , and you may use that in your Compare Bys to measure your campaign performance.</p><p>This is also available in Branch&#39;s <a href="https://help.branch.io/apidocs/query-api" target="_blank" rel="noreferrer">Query API</a> in the <code>last_attributed_touch_data_tilde_keyword_id</code> field in all EO topics.</p><h3 id="keyword-name-and-ad-set-name" tabindex="-1">Keyword name and ad set name <a class="header-anchor" href="#keyword-name-and-ad-set-name" aria-label="Permalink to &quot;Keyword name and ad set name&quot;">​</a></h3><p>With the new framework, Branch is now able to retrieve keyword names and Ad set names for Apple Search Campaigns, and you may use that in your Compare Bys to measure your campaign performance.</p><h2 id="data-mapping-and-reporting" tabindex="-1">Data mapping and reporting <a class="header-anchor" href="#data-mapping-and-reporting" aria-label="Permalink to &quot;Data mapping and reporting&quot;">​</a></h2><p>Branch fetches two <a href="https://developer.apple.com/documentation/apple_search_ads/reports" target="_blank" rel="noreferrer">types of reports</a> from the Apple Ads API: keyword-level and ad-level.</p><p>These reports are different, but they share some fields in common. The tables below outline which fields are exclusively in keyword-level reports, which fields are exclusively in ad-level reports, and which fields are in both (universal).</p><p>Additionally, the fields that Branch receives from the Apple API are mapped to Branch fields. These mappings are also included in the tables below.</p><h3 id="keyword-level-fields" tabindex="-1">Keyword-level fields <a class="header-anchor" href="#keyword-level-fields" aria-label="Permalink to &quot;Keyword-level fields&quot;">​</a></h3><p>The following fields are included <strong>only</strong> in keyword-level reports:</p><table tabindex="0"><thead><tr><th>Apple Ads Parameter</th><th>Branch Mapped Field</th></tr></thead><tbody><tr><td><code>keyword</code></td><td><code>last_attributed_touch_data_tilde_keyword</code></td></tr><tr><td><code>keywordId</code></td><td><code>last_attributed_touch_data_tilde_keyword_id</code></td></tr></tbody></table><h3 id="ad-level-fields" tabindex="-1">Ad-level fields <a class="header-anchor" href="#ad-level-fields" aria-label="Permalink to &quot;Ad-level fields&quot;">​</a></h3><p>The following fields are included <strong>only</strong> in ad-level reports:</p><table tabindex="0"><thead><tr><th>Apple Ads Parameter</th><th>Branch Mapped Field</th></tr></thead><tbody><tr><td><code>adName</code></td><td><code>last_attributed_touch_data_tilde_ad_name</code></td></tr><tr><td><code>adId</code></td><td><code>last_attributed_touch_data_tilde_ad_id</code></td></tr><tr><td><code>creativeName</code></td><td><code>last_attributed_touch_data_tilde_creative_name</code></td></tr><tr><td><code>creativeId</code></td><td><code>last_attributed_touch_data_tilde_creative_id</code></td></tr></tbody></table><h3 id="universal-fields" tabindex="-1">Universal fields <a class="header-anchor" href="#universal-fields" aria-label="Permalink to &quot;Universal fields&quot;">​</a></h3><p>The following fields are included in <strong>both</strong> keyword-level and ad-level reports:</p><table tabindex="0"><thead><tr><th>Apple Ads Parameter</th><th>Branch Mapped Field</th></tr></thead><tbody><tr><td><code>campaignName</code></td><td><code>last_attributed_touch_data_tilde_campaign</code></td></tr><tr><td><code>campaignId</code></td><td><code>last_attributed_touch_data_tilde_campaign_id</code></td></tr><tr><td><code>adGroupName</code></td><td><code>last_attributed_touch_data_tilde_ad_set_name</code></td></tr><tr><td><code>adGroupId</code></td><td><code>last_attributed_touch_data_tilde_ad_set_id</code></td></tr><tr><td><code>orgId</code></td><td><code>last_attributed_touch_data_tilde_advertising_account_name</code></td></tr><tr><td><code>countryOrRegion</code></td><td><code>last_attributed_touch_data_tilde_country_or_region</code></td></tr></tbody></table><h3 id="default-behavior" tabindex="-1">Default behavior <a class="header-anchor" href="#default-behavior" aria-label="Permalink to &quot;Default behavior&quot;">​</a></h3><p>Since some fields are included in both keyword-level and ad-level reports, Branch prevents duplication by setting a default data source to pull from when dimensions from both types of reports are requested.</p><p><strong>The default data source is keyword-level reports</strong>.</p><p>This means:</p><ul><li>If only keyword-level (or keyword-level and universal) dimensions are pulled, then the keyword-level report is the data source.</li><li>If only ad-level (or ad-level and universal) dimensions are pulled, then the ad-level report is the data source.</li><li>If both keyword-level and ad-level (or keyword-level, ad-level, and universal) dimensions are pulled, then the keyword-level report is the data source.</li></ul><h3 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h3><p>Branch recommends that you set up two reports: a keyword-level report and an ad-level report, to mirror the setup of the Apple API reporting structure.</p><p>For the keyword-level report, include as many keyword-level and universal dimensions as you are interested.</p><p>For the ad-level report, include as many ad-level and universal dimensions as you are interested in.</p><p>For simplicity, avoid including exclusively keyword-level and exclusively ad-level fields in the same report.</p>',36)])])}const m=a(o,[["render",i]]);export{u as __pageData,m as default};
